={
  "model": "llama-3.1-70b-versatile",
  "messages": [
    {
      "role": "system",
      "content": "You are a lead qualification assistant. Score leads 1-10 based on these ICP criteria:\n- Company size: 20-200 employees (ideal)\n- Industry: SaaS, Agency, or E-commerce (ideal)\n- Need: Automation, AI agents, or workflow optimization\n- Budget signals: mentions growth, scaling, or specific tools\n\nRespond with ONLY valid JSON, no other text: {\"score\": number, \"reasoning\": \"brief explanation\", \"qualified\": boolean}"
    },
    {
      "role": "user",
      "content": "Lead info:\nName: {{ $('New Lead Webhook').item.json.name }}\nCompany: {{ $('New Lead Webhook').item.json.company }}\nMessage: {{ $('New Lead Webhook').item.json.message }}"
    }
  ],
  "temperature": 0.3
}

parameters.jsCode:
// Parse the LLM response
const response = $input.first().json;
const content = response.choices[0].message.content;

let parsed;
try {
  // Try to parse JSON from LLM response
  parsed = JSON.parse(content);
} catch (e) {
  // Fallback if LLM doesn't return clean JSON
  parsed = { score: 5, reasoning: "Could not parse response", qualified: false };
}

// Combine original lead data with scoring
const leadData = $('New Lead Webhook').item.json;

return [{
  json: {
    ...leadData,
    lead_score: parsed.score,
    score_reasoning: parsed.reasoning,
    is_qualified: parsed.qualified || parsed.score >= 7,
    scored_at: new Date().toISOString()
  }
}];

